function solve(n) {
    // Map to store sum -> count of ways it can be represented as a^3 + b^3
    const sumCounts = new Map();

    // Iterate over possible values for 'a'. Since a <= b, we must have 2*a^3 <= N.
    for (let a = 1; ; a++) {
        const aCubed = a * a * a;

        // Optimization: If 2 * a^3 exceeds N, no further sums can be valid.
        // Use BigInt comparison if N were larger, but for N <= 10^9, standard numbers are safe.
        if (aCubed * 2 > n) {
            break;
        }

        // Iterate over possible values for 'b', starting from 'a'
        for (let b = a; ; b++) {
            const bCubed = b * b * b;
            const x = aCubed + bCubed;

            if (x > n) {
                // Since b is increasing, all subsequent sums will also exceed N.
                break;
            }

            // Record the sum frequency
            sumCounts.set(x, (sumCounts.get(x) || 0) + 1);
        }
    }

    // Collect all sums that appeared at least twice
    const goodIntegers = [];
    for (const [sum, count] of sumCounts.entries()) {
        if (count >= 2) {
            goodIntegers.push(sum);
        }
    }

    // Return the results sorted in ascending order
    return goodIntegers.sort((a, b) => a - b);
