func solve(n int64) []int64 {
	// Map to store sum -> count of ways it can be represented as a^3 + b^3
	sumCounts := make(map[int64]int)

	cube := func(k int64) int64 {
		return k * k * k
	}

	// Iterate over possible values for 'a'. 
	a := int64(1)
	for {
		aCubed := cube(a)

